			\pgfmathsetmacro{\xct}{xct}
			\pgfmathsetmacro{\xcd}{xcd}
			\pgfmathsetmacro{\yct}{yct}
			\pgfmathsetmacro{\ycd}{ycd}
			\pgfmathsetmacro{\tcd}{tcd}

			\clip (\xmin,\ymin) rectangle (\xmax,\ymax);

			\draw[->] (\xmin,0)--(\xmax,0) node[below, xshift=-5pt] {$x$};
			\draw[->] (0,\ymin)--(0, \ymax) node[right, yshift=-5pt] {$y$};

			\draw[dashed] (xct,0)|-(0,yct);
			\draw[dashed] (xcd,0)|-(0,ycd);

			\foreach \x in {-3,-2,-1,1,2,3,4,5,6}
			\draw (\x,0.05)--(\x,-0.05);
			\foreach \y in {-4,-3,-2,-1,1,2,3,4,5}
			\draw (0.05,\y)--(-0.05,\y);
