			\draw[blue]
			plot [domain=\xmin:{tcd-0.05}, samples=200, smooth](\x,{f(\x)})
			plot [domain={tcd+0.05}:\xmax, samples=200, smooth](\x,{f(\x)});

			\fill[draw, fill=red](0,0)circle(1.5pt)node[above left]{$O$};
			\foreach \x/\y in {0/0, xct/yct, xcd/ycd}
			\fill[draw, fill=red](\x,\y)circle(1.5pt);
	\end{tikzpicture}

